import java.util.Optional;

public class Main {
    public static Optional<String> findName(int id) {
        if (id == 1) {
            return Optional.of("Alice");
        } else if (id == 2) {
            return Optional.of("Bob");
        }
        return Optional.empty();
    }

    public static void main(String[] args) {
        // id = 1 exists
        Optional<String> result1 = findName(1);
        System.out.println("Found: " + result1.orElse("Unknown"));
        result1.ifPresent(name -> System.out.println("Hello, " + name));

        // id = 3 doesn't exist
        Optional<String> result2 = findName(3);
        System.out.println("Found: " + result2.orElse("Default User"));
        System.out.println("OrElseGet: " + result2.orElseGet(() -> "Generated"));

        // with map and filter
        Optional<String> transformed = result1
            .map(String::toUpperCase)
            .filter(s -> s.startsWith("A"));
        System.out.println("Transformed: " + transformed.orElse("none"));
    }
}
